(()=>{"use strict";window.addEventListener("load",function(){const e=document.querySelectorAll(".container-element"),t={_element:document.querySelector("#H-info"),update(e){this._element.classList.add("non-display"),e.classList.remove("non-display"),this._element=e}};e.forEach(e=>{e.addEventListener("click",()=>{const n=document.querySelector(`#${e.id}-info`);t.update(n)})})})})();